async function kvList(env, key) {
  if (key === 'plt:boutiques') {
    // Merge SEED with per-boutique deltas stored in KV (one read, avoids writing 134KB on every PUT)
    let deltas = {};
    try { const r = await env.KV.get('plt:boutique_deltas'); if (r) deltas = JSON.parse(r); } catch {}
    if (!Object.keys(deltas).length) return BOUTIQUES_SEED;
    const seedIds = new Set(BOUTIQUES_SEED.map(b => b.id));
    const merged = BOUTIQUES_SEED
      .filter(b => !deltas[b.id]?._deleted)
      .map(b => deltas[b.id] ? {...b, ...deltas[b.id]} : b);
    for (const [id, b] of Object.entries(deltas)) { if (!seedIds.has(id) && !b._deleted) merged.unshift(b); }
    const DELETED_IDS = new Set(['7dc08b86']); // bitiba.fr supprimé manuellement (quota KV)
    return merged.filter(b => !DELETED_IDS.has(b.id) && b.aliexpress_pct !== null && (b.aliexpress_pct ?? -1) >= 80);
  }
  try { const r = await env.KV.get(key); return r ? JSON.parse(r) : []; } catch { return []; }
}
async function kvSet(env, key, val) {
  await env.KV.put(key, JSON.stringify(val));
}
async function kvSetSafe(env, key, val) {
  try { await env.KV.put(key, JSON.stringify(val)); return true; }
  catch(e) { return false; }
}
async function saveBoutique(env, list, boutique) {
  let deltas = {};
  try { const r = await env.KV.get('plt:boutique_deltas'); if (r) deltas = JSON.parse(r); } catch {}
  deltas[boutique.id] = boutique;
  const ok = await kvSetSafe(env, 'plt:boutique_deltas', deltas);
  const i = list.findIndex(b => b.id === boutique.id);
  if (i >= 0) list[i] = boutique; else list.unshift(boutique);
  return ok;
}
// Find boutique by id from list (no individual key lookup)

function findBoutique(list, id) {
  return list.find(b => b.id === id) || null;
}

function requireAuth(request, env) {
  if (!env.API_TOKEN) return err('Server misconfigured', 500);
  const auth = request.headers.get('Authorization') || '';
  if (auth !== `Bearer ${env.API_TOKEN}`) return err('Unauthorized', 401);
  return null;
}

export default {
  async scheduled(event, env, ctx) {
    const base = 'https://v35-build-api.ernestpedanou.workers.dev/api';
    const h = new Date().getUTCHours();
    // Every run: pipeline
    ctx.waitUntil(fetch(`${base}/pipeline/run`, {
      method:'POST', headers:{'Content-Type':'application/json'},
      body: JSON.stringify({trigger:'cron', secret: env.SEED_SECRET})
    }));
    // Every 6h (0,6,12,18): health check sweep (lightweight — just fetch each domain HEAD)
    if (h % 6 === 0) {
      ctx.waitUntil((async () => {
        try {
          const r = await fetch(`${base}/boutiques?per=300`);
          const data = await r.json();
          const now = Date.now();
          for (const b of (data.list || []).slice(0, 30)) { // batch of 30 per cron
            if (b.last_checked && now - b.last_checked < 6*3600000) continue;
            try {
              const res = await fetch(`https://${b.domain}`, { method: 'HEAD', redirect:'follow',
                headers:{'User-Agent':'V35HealthBot/1.0'}, signal: AbortSignal.timeout(5000) });
              await fetch(`${base}/boutiques/${b.id}`, {
                method:'PUT', headers:{'Content-Type':'application/json','Authorization':`Bearer ${env.API_TOKEN}`},
                body: JSON.stringify({ online: res.status < 400, http_status: res.status, last_checked: now })
              });
            } catch { await fetch(`${base}/boutiques/${b.id}`, {
              method:'PUT', headers:{'Content-Type':'application/json','Authorization':`Bearer ${env.API_TOKEN}`},
              body: JSON.stringify({ online: false, http_status: 0, last_checked: now })
            }); }
          }
        } catch {}
      })());
    }
  },
  async fetch(request, env) {
    try {
    if (request.method === 'OPTIONS') return new Response(null, { headers: CORS });
    const url = new URL(request.url);
    const [,, resource, id, sub] = url.pathname.split('/');
    const method = request.method;
    let body = {};
    if (method === 'POST' || method === 'PUT') { try { body = await request.json(); } catch {} }


    // ── /api/stats ───────────────────────────────────────────────────────────
    if (resource === 'stats') {
      const [boutiques, sites, jobs, domaines] = await Promise.all([
        kvList(env,'plt:boutiques'), kvList(env,'plt:sites'),
        kvList(env,'plt:jobs'), kvList(env,'plt:domaines'),
      ]);
      const now = Date.now(), month = 30*86400000;
      const sitesLive = sites.filter(s=>s.status==='live');
      const sitesThisMonth = sitesLive.filter(s=>s.createdAt>now-month);
      const boutiquesThisMonth = boutiques.filter(b=>b.createdAt>now-month);
      return ok({
        boutiques: boutiques.length,
        boutiques_qualified: boutiques.filter(b=>['qualified','cloner'].includes(b.importStatus)).length,
        boutiques_winners: boutiques.filter(b=>b.importStatus==='cloner').length,
        footprints: boutiques.filter(b=>b.footprint).length,
        sites_total: sites.length, sites_live: sitesLive.length,
        jobs_total: jobs.length, jobs_done: jobs.filter(j=>j.status==='done').length,
        domaines: domaines.length, domaines_aged: domaines.filter(d=>d.aged).length,
        boutiques_this_month: boutiquesThisMonth.length,
        velocity: sitesThisMonth.length,  // sites clonés ce mois (pas boutiques qualifiées)
      });
    }

    // ── /api/pipeline/status ─────────────────────────────────────────────────
    if (resource === 'pipeline' && id === 'status') {
      const [jobs, boutiques] = await Promise.all([kvList(env,'plt:jobs'), kvList(env,'plt:boutiques')]);
      const today = new Date(); today.setHours(0,0,0,0);
      const todayJobs = jobs.filter(j=>j.createdAt>today.getTime());
      const running = boutiques.filter(b=>['orchestrating','running'].includes(b.importStatus));
      return ok({
        jobs_today: todayJobs.length, jobs_running: running.length,
        jobs_done: jobs.filter(j=>j.status==='done').length,
        jobs_pending: jobs.filter(j=>j.status==='pending').length,
        success_rate: jobs.length ? Math.round(jobs.filter(j=>j.status==='done').length/jobs.length*100) : 0,
        running_boutiques: running.map(b=>({id:b.id,domain:b.domain,status:b.importStatus,updatedAt:b.updatedAt})),
      });
    }

    // ── /api/import/csv ──────────────────────────────────────────────────────
    if (resource === 'import' && id === 'csv') {
      if (method !== 'POST') return err('POST required');
      const authErr = requireAuth(request, env);
      if (authErr) return authErr;
      const list = await kvList(env,'plt:boutiques');
      const existing = new Set(list.map(b=>b.domain));
      const created = [];
      for (const row of (body.rows||[])) {
        if (!row.domain || existing.has(row.domain)) continue;
        const b = {
          id:uid(), domain:row.domain, type:row.type||'shopify',
          niche:row.niche||'', traffic:+row.traffic||0, comment:row.comment||'',
          footprint:true, importStatus:'pending', blueprint:null,
          sites:[], jobs:[], keywords:[], images:[], collections:0, products:0,
          createdAt:Date.now(), updatedAt:Date.now(),
        };
        list.unshift(b);
        created.push(b);
        existing.add(b.domain);
      }
      await kvSet(env,'plt:boutiques',list);
      return ok({ created:created.length, skipped:(body.rows||[]).length-created.length });
    }

    // ── /api/rdap/:domain — âge domaine via rdap.org ────────────────────────
    if (resource === 'rdap' && id) {
      const domain = id.toLowerCase().replace(/[^a-z0-9.-]/g,'');
      if (!domain) return err('Invalid domain');
      try {
        const r = await fetch(`https://rdap.org/domain/${domain}`, {
          headers:{'User-Agent':'Mozilla/5.0'}, signal:AbortSignal.timeout(6000)
        });
        if (!r.ok) return ok({ domain, reg_year:null, domain_age_years:null });
        const data = await r.json();
        let reg_year = null, domain_age_years = null;
        for (const ev of (data.events||[])) {
          if (ev.eventAction === 'registration' && ev.eventDate) {
            const dt = new Date(ev.eventDate);
            reg_year = dt.getFullYear();
            domain_age_years = +((Date.now() - dt.getTime()) / 31557600000).toFixed(1);
            break;
          }
        }
        return ok({ domain, reg_year, domain_age_years });
      } catch(e) { return ok({ domain, reg_year:null, domain_age_years:null, error:e.message }); }
    }

    // ── /api/aged-domains/score ──────────────────────────────────────────────
    if (resource === 'aged-domains' && id === 'score') {
      if (method !== 'POST') return err('POST required');
      const { ageDays=0, snapshotCount=1, tld='' } = body;
      const PREMIUM = ['.fr','.com','.de','.es','.it','.net','.be','.ch'];
      const tldScore = PREMIUM.includes(tld) ? 30 : 10;
      const ageScore = Math.min(40, Math.round(ageDays/3650*40));
      const snapScore = Math.min(30, Math.round(Math.log10(snapshotCount+1)*12));
      return ok({ score:ageScore+snapScore+tldScore, breakdown:{age:ageScore,snapshots:snapScore,tld:tldScore} });
    }

    // ── /api/content (proxy → content-ai) ───────────────────────────────────
    if (resource === 'content') {
      const path = url.pathname.replace('/api/content', '/api') || '/api/health';
      try {
        const r = await fetch(WORKERS.CONTENT_AI+path, { method, headers:{'Content-Type':'application/json'}, body:method==='POST'?JSON.stringify(body):undefined, signal:AbortSignal.timeout(30000) });
        const d = await r.json();
        return Response.json(d, { headers:CORS });
      } catch(e) { return err('Content AI unavailable: '+e.message); }
    }

    // ── /api/seo (proxy → seo-engine) ───────────────────────────────────────
    if (resource === 'seo') {
      const path = url.pathname.replace('/api/seo', '/api') || '/api/health';
      try {
        const r = await fetch(WORKERS.SEO_ENGINE+path, { method, headers:{'Content-Type':'application/json'}, body:method==='POST'?JSON.stringify(body):undefined, signal:AbortSignal.timeout(15000) });
        const d = await r.json();
        return Response.json(d, { headers:CORS });
      } catch(e) { return err('SEO Engine unavailable: '+e.message); }
    }

    // ── /api/monitoring ──────────────────────────────────────────────────────
    if (resource === 'monitoring') {
      const checks = await Promise.allSettled(
        Object.entries(WORKERS).map(async ([name, wurl]) => {
          const t0 = Date.now();
          try {
            const r = await fetch(wurl, { method:'GET', signal:AbortSignal.timeout(5000) });
            return { name, url:wurl, status:r.status<500?'up':'down', latency:Date.now()-t0 };
          } catch(e) { return { name, url:wurl, status:'down', latency:Date.now()-t0, error:e.message }; }
        })
      );
      const workers = checks.map(r=>r.status==='fulfilled'?r.value:{name:'?',status:'error'});
      const up = workers.filter(w=>w.status==='up').length;
      return ok({ workers, up, total:workers.length, health:Math.round(up/workers.length*100) });
    }

    // ── /api/seed (bypasses CF REST API quota — uses Worker KV binding directly)
    if (resource === 'seed') {
      if (method !== 'POST') return err('POST required');
      const secret = request.headers.get('X-Seed-Secret') || body.secret || '';
      if (!env.SEED_SECRET) return err('Server misconfigured', 500);
      if (secret !== env.SEED_SECRET) return err('Unauthorized', 401);
      const results = {};
      if (body.boutiques) {
        const ok1 = await kvSetSafe(env, 'plt:boutiques', body.boutiques);
        results.boutiques = ok1 ? body.boutiques.length : 'kv_write_failed';
      }
      if (body.homepages) {
        const ok2 = await kvSetSafe(env, 'plt:homepages', body.homepages);
        results.homepages = ok2 ? Object.keys(body.homepages).length : 'kv_write_failed';
      }
      return ok({ seeded: results });
    }

    // ── /api/boutiques ───────────────────────────────────────────────────────
    if (resource === 'boutiques' || resource === 'footprints') {
      const isFootprint = resource === 'footprints';
      // ── POST /api/boutiques/purge — bulk delete, une seule écriture KV ──────
      // ── POST /api/boutiques/scrape-all — scrape collections+produits pour toutes les boutiques sans collections
      if (id === 'scrape-all' && method === 'POST') {
        const authErr = requireAuth(request, env); if (authErr) return authErr;
        const list = await kvList(env,'plt:boutiques');
        const targets = list.filter(b => !b.collections || b.collections === 0);
        const results = [];
        for (const boutique of targets) {
          try {
            const r = await fetch(WORKERS.SCRAPER+'/api/scrape', {
              method:'POST', headers:{'Content-Type':'application/json'},
              body:JSON.stringify({domain:boutique.domain}), signal:AbortSignal.timeout(25000)
            });
            const d = await r.json();
            let cols = d.collections?.length || 0, prods = 0;
            // Fallback direct pour Shopify si scraper ne renvoie rien
            if (!cols) {
              try {
                const rs = await fetch(`https://${boutique.domain}/collections.json?limit=250`, { signal:AbortSignal.timeout(10000) });
                const ds = await rs.json();
                cols = ds.collections?.length || 0;
              } catch {}
            }
            if (!cols) {
              try {
                const rp = await fetch(`https://${boutique.domain}/wp-json/wc/v3/products/categories?per_page=100`, { signal:AbortSignal.timeout(10000) });
                const dp = await rp.json();
                cols = Array.isArray(dp) ? dp.length : 0;
              } catch {}
            }
            if (cols > 0) {
              boutique.collections = d.collections?.length ? d.collections.length : cols;
              boutique.products = d.collections?.length ? d.collections.reduce((s,c)=>s+(c.products||0),0) : prods;
              boutique.importStatus = 'scraped';
              if (d.collections?.length) boutique.blueprint = {source:boutique.domain, collections:d.collections, totalCollections:d.collections.length};
              boutique.updatedAt = Date.now();
              await saveBoutique(env, list, boutique);
              results.push({domain:boutique.domain, collections:boutique.collections, products:boutique.products, ok:true});
            } else {
              results.push({domain:boutique.domain, collections:0, products:0, ok:false, error:d.error||'no collections found'});
            }
          } catch(e) {
            results.push({domain:boutique.domain, ok:false, error:e.message});
          }
        }
        return ok({ scraped: results.filter(r=>r.ok).length, failed: results.filter(r=>!r.ok).length, results });
      }

      if (id === 'purge' && method === 'POST') {
        const authErr = requireAuth(request, env); if (authErr) return authErr;
        const ids = new Set(body.ids || []);
        if (!ids.size) return err('ids[] requis');
        const list = await kvList(env,'plt:boutiques');
        const kept = list.filter(b => !ids.has(b.id));
        const removed = list.length - kept.length;
        const payload = JSON.stringify(kept);
        const bytes = new TextEncoder().encode(payload).length;
        try {
          await env.KV.put('plt:boutiques', payload);
        } catch(e) {
          return err(`KV write failed: ${e?.message} (${bytes} bytes, ${kept.length} items)`, 503);
        }
        return ok({ removed, kept: kept.length, bytes });
      }

      if (!id) {
        if (method === 'GET') {
          let list = await kvList(env,'plt:boutiques');
          if (isFootprint) list = list.filter(b=>b.footprint);
          const q = url.searchParams;
          if (q.get('type')) list=list.filter(b=>b.type===q.get('type'));
          if (q.get('niche')) list=list.filter(b=>b.niche===q.get('niche'));
          if (q.get('status')) list=list.filter(b=>b.importStatus===q.get('status'));
          if (q.get('q')) { const s=q.get('q').toLowerCase(); list=list.filter(b=>b.domain?.includes(s)); }
          if (q.get('ali_min')) list=list.filter(b=>(b.aliexpress_pct||0)>=+q.get('ali_min'));
          if (q.get('ali_max')) list=list.filter(b=>(b.aliexpress_pct||0)<=+q.get('ali_max'));
          const BASKET_CA = { bijoux:85, mode:55, beaute:45, sport:65, maison:75, electronique:120, nutrition:40, animaux:35, sante:50, luxe:200, auto:80, jardin:45, enfant:40 };
          const caMonthly = b => Math.round((b.traffic||0)*0.02*(BASKET_CA[b.niche]||50));
          if (q.get('sort')==='traffic') list.sort((a,b)=>(b.traffic||0)-(a.traffic||0));
          else if (q.get('sort')==='score') list.sort((a,b)=>(b.score||0)-(a.score||0));
          else if (q.get('sort')==='ca') list.sort((a,b)=>caMonthly(b)-caMonthly(a));
          list = list.map(b=>({...b, ca_monthly: caMonthly(b)}));
          const page=Math.max(1,+q.get('page')||1), per=+q.get('per')||25, total=list.length;
          return ok({ list:list.slice((page-1)*per,page*per), total, page, pages:Math.ceil(total/per) });
        }
        if (method === 'POST') {
          const authErr = requireAuth(request, env); if (authErr) return authErr;
          const list = await kvList(env,'plt:boutiques');
          const b = {
            id:uid(), domain:body.domain, type:body.type||'shopify',
            niche:body.niche||'', theme:body.theme||'', traffic:body.traffic||0,
            collections:0, products:0, importStatus:'pending', comment:body.comment||'',
            footprint:isFootprint||body.footprint||false,
            blueprint:null, sites:[], jobs:[], keywords:[], images:[],
            createdAt:Date.now(), updatedAt:Date.now(),
          };
          const saved = await saveBoutique(env, list, b);
          if (!saved) return err('KV write limit reached — try again after midnight UTC', 503);
          return ok({boutique:b},201);
        }
      }
      // Individual boutique ops — load from list (no individual KV key needed)
      const list = await kvList(env,'plt:boutiques');
      const boutique = findBoutique(list, id);
      if (!boutique && method==='GET') return err('Not found',404);
      if (!sub) {
        if (method==='GET') return ok({boutique});
        if (method==='PUT') {
          const authErr = await requireAuth(request, env); if (authErr) return authErr;
          const BOUTIQUE_FIELDS = ['domain','type','niche','traffic','comment','importStatus','blueprint','collections','products','profitable_collections','footprint','keywords','images','sites','jobs','score','cpc','traffic_monthly','online','http_status','last_checked','redirect_url','clone_days','ca_monthly','aliexpress_pct','aliexpress_detail','aliexpress_checked_at','aliexpress_supplier_url','expired_domain'];
          for (const k of BOUTIQUE_FIELDS) if (k in body) boutique[k] = body[k];
          boutique.updatedAt = Date.now();
          await saveBoutique(env, list, boutique);
          return ok({boutique});
        }
        if (method==='DELETE') {
          const authErr = await requireAuth(request, env); if (authErr) return authErr;
          // 1 seule écriture KV : marquer _deleted dans les deltas (kvList filtre déjà _deleted)
          let deltas = {};
          try { const r = await env.KV.get('plt:boutique_deltas'); if (r) deltas = JSON.parse(r); } catch {}
          deltas[id] = { _deleted: true };
          const saved = await kvSetSafe(env, 'plt:boutique_deltas', deltas);
          if (!saved) return err('KV write limit reached — retry after midnight UTC', 503);
          try { await env.KV.delete(`plt:scrape:${id}`); } catch {}
          return ok({deleted:id});
        }
      }
      if (sub==='scrape') {
        const authErr = requireAuth(request, env); if (authErr) return authErr;
        const scraperTarget = WORKERS.SCRAPER+'/api/scrape';
        let d = {};
        try {
          const r = await fetch(scraperTarget,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({domain:boutique.domain}),signal:AbortSignal.timeout(30000)});
          d = await r.json();
        } catch {
          const r2 = await fetch(WORKERS.SEQ,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({action:'scrape-collections',domain:boutique.domain}),signal:AbortSignal.timeout(25000)});
          d = await r2.json();
        }
        if (d.collections?.length) {
          boutique.blueprint={source:boutique.domain,collections:d.collections,totalCollections:d.collections.length};
          boutique.collections=d.collections.length;
          boutique.products=d.collections.reduce((s,c)=>s+(c.products||0),0);
          boutique.importStatus='scraped';
          if (d.niches?.[0] && !boutique.niche) boutique.niche=d.niches[0];
          boutique.updatedAt=Date.now();
          await saveBoutique(env, list, boutique);
        }
        return ok({boutique,collections:d.collections?.length||0,error:d.error});
      }
      if (sub==='orchestrate') {
        const authErr = requireAuth(request, env); if (authErr) return authErr;
        const r = await fetch(WORKERS.ORCH,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({sourceDomain:boutique.domain,targetDomain:body.targetDomain||boutique.domain,niche:boutique.niche,languages:body.languages||['fr','de','es'],findAgedDomain:true}),signal:AbortSignal.timeout(60000)});
        const d = await r.json();
        boutique.orchestrateJobId=d.jobId; boutique.importStatus='orchestrating';
        await saveBoutique(env, list, boutique);
        return ok(d);
      }
      return err('Unknown sub-resource',404);
    }

    // ── /api/sites ───────────────────────────────────────────────────────────
    if (resource === 'sites') {
      if (!id) {
        if (method==='GET') {
          let list=await kvList(env,'plt:sites');
          const q=url.searchParams;
          if(q.get('niche')) list=list.filter(s=>s.niche===q.get('niche'));
          if(q.get('status')) list=list.filter(s=>s.status===q.get('status'));
          if(q.get('lang')) list=list.filter(s=>s.languages?.includes(q.get('lang')));
          const page=Math.max(1,+q.get('page')||1),per=+q.get('per')||25,total=list.length;
          return ok({list:list.slice((page-1)*per,page*per),total,page,pages:Math.ceil(total/per)});
        }
        if (method==='POST') {
          const authErr = requireAuth(request, env); if (authErr) return authErr;
          const list=await kvList(env,'plt:sites');
          const s={id:uid(),domain:body.domain,sourceDomain:body.sourceDomain,niche:body.niche||'',languages:body.languages||['fr'],status:body.status||'pending',fileCount:0,palette:{},serverUrl:body.serverUrl||'',pages:body.pages||0,createdAt:Date.now(),updatedAt:Date.now()};
          list.unshift(s); await kvSet(env,'plt:sites',list); await kvSet(env,`plt:site:${s.id}`,s);
          return ok({site:s},201);
        }
      }
      if (method==='GET') { const s=JSON.parse(await env.KV.get(`plt:site:${id}`)||'null'); return s?ok({site:s}):err('Not found',404); }
      if (method==='PUT') {
        const authErr = requireAuth(request, env); if (authErr) return authErr;
        const s=JSON.parse(await env.KV.get(`plt:site:${id}`)||'null'); if(!s) return err('Not found',404);
        const SITE_FIELDS=['domain','sourceDomain','niche','languages','status','fileCount','palette','serverUrl','pages'];
        for(const k of SITE_FIELDS) if(k in body) s[k]=body[k]; s.updatedAt=Date.now();
        await kvSet(env,`plt:site:${id}`,s);
        const list=await kvList(env,'plt:sites'); const i=list.findIndex(x=>x.id===id); if(i>=0) list[i]=s;
        await kvSet(env,'plt:sites',list); return ok({site:s});
      }
    }

    // ── /api/jobs ────────────────────────────────────────────────────────────
    if (resource === 'jobs') {
      if (method==='GET') {
        let list=await kvList(env,'plt:jobs');
        const q=url.searchParams;
        if(q.get('type')) list=list.filter(j=>j.type===q.get('type'));
        if(q.get('status')) list=list.filter(j=>j.status===q.get('status'));
        if(q.get('site')) list=list.filter(j=>j.site===q.get('site'));
        const page=Math.max(1,+q.get('page')||1),per=30,total=list.length;
        return ok({list:list.slice((page-1)*per,page*per),total,page,pages:Math.ceil(total/per)});
      }
      if (method==='POST') {
        const authErr = requireAuth(request, env); if (authErr) return authErr;
        const list=await kvList(env,'plt:jobs');
        const j={id:uid(),type:body.type||'collection_intro',promptNumero:body.promptNumero||'',prompt:body.prompt||'',langue:body.langue||'fr',pays:body.pays||'FR',site:body.site||'',status:'pending',response:'',score:null,createdAt:Date.now(),updatedAt:Date.now()};
        list.unshift(j); await kvSet(env,'plt:jobs',list); return ok({job:j},201);
      }
      if (method==='PUT'&&id) {
        const authErr = requireAuth(request, env); if (authErr) return authErr;
        const list=await kvList(env,'plt:jobs'); const i=list.findIndex(j=>j.id===id);
        if(i<0) return err('Not found',404);
        const JOB_FIELDS=['status','response','score','type','promptNumero','prompt','langue','pays','site'];
        for(const k of JOB_FIELDS) if(k in body) list[i][k]=body[k]; list[i].updatedAt=Date.now();
        await kvSet(env,'plt:jobs',list); return ok({job:list[i]});
      }
    }

    // ── /api/domaines ────────────────────────────────────────────────────────
    if (resource === 'domaines') {
      if (!id) {
        if (method==='GET') {
          let list=await kvList(env,'plt:domaines');
          const q=url.searchParams;
          if(q.get('status')) list=list.filter(d=>d.status===q.get('status'));
          if(q.get('niche')) list=list.filter(d=>d.niche===q.get('niche'));
          if(q.get('aged')) list=list.filter(d=>d.aged);
          return ok({list,total:list.length});
        }
        if (method==='POST') {
          const authErr = requireAuth(request, env); if (authErr) return authErr;
          const list=await kvList(env,'plt:domaines');
          const d={id:uid(),domain:body.domain||'',niche:body.niche||'',aged:!!body.aged,status:body.status||'pending',tld:body.tld||'',ageDays:+body.ageDays||0,snapshots:+body.snapshots||0,note:body.note||'',createdAt:Date.now(),updatedAt:Date.now()};
          list.unshift(d); await kvSet(env,'plt:domaines',list); return ok({domaine:d},201);
        }
      }
      if (method==='PUT'&&id) {
        const authErr = requireAuth(request, env); if (authErr) return authErr;
        const list=await kvList(env,'plt:domaines'); const i=list.findIndex(d=>d.id===id);
        if(i<0) return err('Not found',404);
        const DOM_FIELDS=['domain','niche','aged','status','tld','ageDays','snapshots','note'];
        for(const k of DOM_FIELDS) if(k in body) list[i][k]=body[k]; list[i].updatedAt=Date.now();
        await kvSet(env,'plt:domaines',list); return ok({domaine:list[i]});
      }
      if (method==='DELETE'&&id) {
        const authErr = requireAuth(request, env); if (authErr) return authErr;
        const list=(await kvList(env,'plt:domaines')).filter(d=>d.id!==id);
        await kvSet(env,'plt:domaines',list); return ok({deleted:id});
      }
    }

    // ── /api/images ──────────────────────────────────────────────────────────
    if (resource === 'images') {
      if (method==='GET') return ok({list:await kvList(env,'plt:images')});
      if (method==='POST') {
        const list=await kvList(env,'plt:images');
        const img={id:uid(),...body,addedAt:Date.now()};
        list.unshift(img); if(list.length>500) list.length=500;
        await kvSet(env,'plt:images',list); return ok({image:img},201);
      }
    }

    // ── /api/pipeline/run ────────────────────────────────────────────────────
    if (resource === 'pipeline' && id === 'run') {
      const {sourceDomain,targetDomain,niche,languages=['fr','de','es']} = body;
      if (!sourceDomain||!targetDomain) return err('sourceDomain+targetDomain required');
      const boutiques=await kvList(env,'plt:boutiques');
      const b={id:uid(),domain:sourceDomain,type:'shopify',niche,importStatus:'running',collections:0,products:0,traffic:0,footprint:true,sites:[],createdAt:Date.now(),updatedAt:Date.now()};
      boutiques.unshift(b); await kvSet(env,'plt:boutiques',boutiques); await kvSet(env,`plt:boutique:${b.id}`,b);
      const orchResult = await fetch(WORKERS.ORCH,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({sourceDomain,targetDomain,niche,languages,findAgedDomain:true}),signal:AbortSignal.timeout(55000)}).then(r=>r.json()).catch(()=>null);
      if (orchResult?.jobId) { b.orchestrateJobId=orchResult.jobId; b.importStatus=orchResult.status||'running'; await kvSet(env,`plt:boutique:${b.id}`,b); }
      return ok({boutique:b,orchResult});
    }

    // ── /api/alerts ──────────────────────────────────────────────────────────
    if (resource === 'alerts') {
      const boutiques = await kvList(env,'plt:boutiques');
      const week = 7*86400000;
      const newWinners = boutiques.filter(b => b.importStatus==='cloner' && b.createdAt > Date.now()-week);
      return ok({ count: newWinners.length, winners: newWinners.slice(0,10) });
    }

    // ── /api/scrape ──────────────────────────────────────────────────────────────
    if (resource === 'scrape') {
      const auth = await requireAuth(request, env);
      if (auth && method !== 'GET') return auth;

      // GET /api/scrape/status — all scrape statuses
      if (!id || id === 'status') {
        const all = await kvList(env, 'plt:boutiques');
        const statuses = all.map(b => ({
          id: b.id, domain: b.domain, type: b.type, niche: b.niche,
          scrape_status: b.scrape_status || 'pending',
          scraped_at: b.scraped_at || null,
          products_scraped: b.products_scraped || 0,
          collections_scraped: b.collections_scraped || 0,
          images_cataloged: b.images_cataloged || 0,
        }));
        const done = statuses.filter(s => s.scrape_status === 'done').length;
        return ok({ total: statuses.length, done, pending: statuses.length - done, list: statuses });
      }

      // GET /api/scrape/:id/products — scraped products for one boutique
      if (sub === 'products') {
        const raw = await env.KV.get(`plt:scrape:${id}`);
        if (!raw) return ok({ products: [], total: 0 });
        const data = JSON.parse(raw);
        return ok(data);
      }

      // GET /api/scrape/:id/export.csv — CSV export
      if (sub === 'export.csv') {
        const raw = await env.KV.get(`plt:scrape:${id}`);
        if (!raw) return new Response('domain,handle,title,price_min,price_max,variants,images\n', {
          headers: { 'Content-Type': 'text/csv', 'Content-Disposition': `attachment;filename="${id}.csv"`, ...CORS }
        });
        const { products } = JSON.parse(raw);
        const rows = (products || []).map(p => [
          p.domain || id, p.handle || '', `"${(p.title||'').replace(/"/g,'""')}"`,
          p.price_min || '', p.price_max || '',
          (p.variants||[]).length, (p.images||[]).length
        ].join(','));
        const csv = 'domain,handle,title,price_min,price_max,variants,images\n' + rows.join('\n');
        return new Response(csv, {
          headers: { 'Content-Type': 'text/csv', 'Content-Disposition': `attachment;filename="${id}.csv"`, ...CORS }
        });
      }

      // PUT /api/scrape/:id — store scrape results for a boutique
      if (method === 'PUT') {
        const body = await request.json();
        // Store products separately (can be large)
        if (body.products) {
          await env.KV.put(`plt:scrape:${id}`, JSON.stringify({
            domain: body.domain,
            scraped_at: Date.now(),
            products_total: body.products_total || body.products.length,
            products: body.products
          }), { expirationTtl: 60 * 60 * 24 * 30 }); // 30 days TTL
        }
        // Update boutique metadata
        const list = await kvList(env, 'plt:boutiques');
        const boutique = findBoutique(list, id);
        if (boutique) {
          boutique.scrape_status = 'done';
          boutique.scraped_at = Date.now();
          boutique.products_scraped = body.products_total || (body.products||[]).length;
          boutique.collections_scraped = body.collections_total || 0;
          boutique.images_cataloged = body.images_total || 0;
          await saveBoutique(env, list, boutique);
        }
        return ok({ stored: true, products: (body.products||[]).length });
      }

      // POST /api/scrape/export-all — full CSV of all scraped boutiques  
      if (!id && method === 'POST') {
        const list = await kvList(env, 'plt:boutiques');
        const done = list.filter(b => b.scrape_status === 'done');
        return ok({ exportable: done.length, message: 'Use GET /api/scrape/{id}/export.csv per domain' });
      }

      return err('Not found', 404);
    }


    // ── /api/expired-domains ─────────────────────────────────────────────────
    if (resource === 'expired-domains') {
      const authErr = method !== 'GET' ? await requireAuth(request, env) : null;
      if (authErr) return authErr;

      if (!id && method === 'GET') {
        const list = await kvList(env, 'plt:expired_domains');
        const niche = url.searchParams.get('niche');
        const tld   = url.searchParams.get('tld');
        const per   = parseInt(url.searchParams.get('per') || '200');
        let filtered = list;
        if (niche) filtered = filtered.filter(d => d.niche === niche);
        if (tld)   filtered = filtered.filter(d => d.domain.endsWith('.' + tld));
        filtered.sort((a,b) => (b.score||0)-(a.score||0));
        return ok({ list: filtered.slice(0, per), total: filtered.length });
      }

      if (!id && method === 'POST') {
        const domains = Array.isArray(body) ? body : [body];
        let list = await kvList(env, 'plt:expired_domains');
        const existing = new Set(list.map(d => d.domain));
        let added = 0;
        for (const d of domains) {
          if (!d.domain || existing.has(d.domain)) continue;
          d.id = d.domain.replace(/\./g, '-') + '-' + Date.now();
          d.found_at = Date.now();
          list.unshift(d);
          existing.add(d.domain);
          added++;
        }
        // Keep max 2000 domains
        list = list.slice(0, 2000);
        await kvSetSafe(env, 'plt:expired_domains', list);
        return ok({ added, total: list.length });
      }

      if (id === 'match' && sub) {
        // GET /api/expired-domains/match/:boutique_id — best expired domain for a boutique
        const blist = await kvList(env, 'plt:boutiques');
        const b = blist.find(x => x.id === sub);
        if (!b) return err('Boutique not found', 404);
        const dlist = await kvList(env, 'plt:expired_domains');
        const matches = dlist
          .filter(d => d.niche === b.niche && !d.linked_boutique_id)
          .sort((a,b) => (b.score||0)-(a.score||0));
        return ok({ matches: matches.slice(0, 5) });
      }

      if (id && method === 'PUT') {
        let list = await kvList(env, 'plt:expired_domains');
        const idx = list.findIndex(d => d.id === id || d.domain === id);
        if (idx < 0) return err('Not found', 404);
        Object.assign(list[idx], body);
        await kvSetSafe(env, 'plt:expired_domains', list);
        return ok({ domain: list[idx] });
      }

      if (id && method === 'DELETE') {
        let list = await kvList(env, 'plt:expired_domains');
        list = list.filter(d => d.id !== id && d.domain !== id);
        await kvSetSafe(env, 'plt:expired_domains', list);
        return ok({ deleted: id });
      }

      return err('Not found', 404);
    }

    // ── /api/proxy/search — proxy DDG Lite search (contourne firewall local) ──
    if (resource === 'proxy' && id === 'search') {
      const q = url.searchParams.get('q');
      if (!q) return err('Missing q', 400);
      try {
        const ddgUrl = `https://lite.duckduckgo.com/lite/?q=${encodeURIComponent(q)}`;
        const r = await fetch(ddgUrl, {
          headers: { 'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 Chrome/124.0.0.0 Safari/537.36', 'Accept': 'text/html,*/*' },
          redirect: 'follow',
        });
        const text = await r.text();
        const count = (text.match(/aliexpress\.com/g) || []).length;
        return new Response(JSON.stringify({ ok: true, count, status: r.status }), {
          headers: { ...CORS, 'Content-Type': 'application/json' }
        });
      } catch(e) {
        return new Response(JSON.stringify({ ok: false, count: 0, error: String(e) }), {
          headers: { ...CORS, 'Content-Type': 'application/json' }
        });
      }
    }

    // ── /api/cron/health — endpoint déclenché par cron-job.org (gratuit) ─────
    if (resource === 'cron' && id === 'health') {
      const secret = url.searchParams.get('secret') || body.secret;
      if (secret !== env.SEED_SECRET) return err('Unauthorized', 401);
      // Health sweep: check up to 20 boutiques not checked in last 6h
      const list = await kvList(env, 'plt:boutiques');
      const now = Date.now();
      const stale = list.filter(b => !b.last_checked || now - b.last_checked > 6*3600*1000).slice(0, 20);
      const results = [];
      for (const b of stale) {
        try {
          const r = await fetch(`https://${b.domain}`, {
            method: 'HEAD', redirect: 'follow',
            headers: { 'User-Agent': 'V35HealthBot/1.0' },
            signal: AbortSignal.timeout(5000),
          });
          const up = r.status < 400;
          await fetch(`https://v35-build-api.ernestpedanou.workers.dev/api/boutiques/${b.id}`, {
            method: 'PUT', headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${env.API_TOKEN}` },
            body: JSON.stringify({ online: up, http_status: r.status, last_checked: now }),
          });
          results.push({ domain: b.domain, status: r.status, online: up });
        } catch {
          results.push({ domain: b.domain, status: 0, online: false });
        }
      }
      return ok({ checked: results.length, results });
    }

    // ── /api/cron/auto-purge — exécuté à 00:05 UTC par GitHub Actions ────────
    if (resource === 'cron' && id === 'auto-purge' && method === 'POST') {
      const authErr = requireAuth(request, env); if (authErr) return authErr;
      const allBoutiques = await kvList(env, 'plt:boutiques'); // déjà filtré >= 80 par code
      // Charger les deltas bruts pour y ajouter les _deleted sans perdre les autres entrées
      let deltas = {};
      try { const r = await env.KV.get('plt:boutique_deltas'); if (r) deltas = JSON.parse(r); } catch {}
      // Reconstruire la liste complète SEED (sans filtre) pour trouver les boutiques < 80
      const rawMerged = (() => {
        const seedIds = new Set(BOUTIQUES_SEED.map(b => b.id));
        const m = BOUTIQUES_SEED
          .filter(b => !deltas[b.id]?._deleted)
          .map(b => deltas[b.id] ? {...b, ...deltas[b.id]} : b);
        for (const [id, b] of Object.entries(deltas)) { if (!seedIds.has(id) && !b._deleted) m.unshift(b); }
        return m;
      })();
      const toDelete = rawMerged.filter(b => b.aliexpress_pct === null || (b.aliexpress_pct ?? -1) < 80);
      const FORCE_DELETE = new Set(['7dc08b86']); // bitiba.fr
      const allToDelete = [...toDelete.map(b=>b.id), ...FORCE_DELETE];
      let marked = 0;
      for (const id of allToDelete) { if (!deltas[id]?._deleted) { deltas[id] = { _deleted: true }; marked++; } }
      if (!marked) return ok({ skipped: true, reason: 'nothing to purge' });
      try {
        await env.KV.put('plt:boutique_deltas', JSON.stringify(deltas));
        return ok({ purged: marked, total_deleted: allToDelete.length });
      } catch(e) {
        return err(`KV write failed: ${e?.message}`, 503);
      }
    }

    // ── /api/cron/status — healthcheck pour cron-job.org monitoring ──────────
    if (resource === 'cron' && id === 'status') {
      return ok({ ok: true, ts: Date.now(), version: 'v35-build-api' });
    }

    return err('Not found',404);
    } catch(e) {
      return Response.json({ ok:false, error: e?.message || 'Internal error' }, { status:500, headers:CORS });
    }
  }
};
